com.mirth.connect.plugins.javascriptstep.script:
var snapshot = JSON.parse(msg);
channelMap.put('ts', snapshot.timestamp || new Date().toISOString());

var crrt = snapshot.devices &&
           snapshot.devices.crrt &&
           snapshot.devices.crrt.readings
         ? snapshot.devices.crrt.readings
         : {};

channelMap.put('crrt', crrt);
logger.info('CRRT snapshot parsed: ' + snapshot.timestamp +
            ' | mode=' + (crrt.mode || 'unknown') +
            ' | status=' + (crrt.therapy_status || 'unknown'));

// -----------------------------------------------------------------------
// HL7 v2.5.1 ORU^R01 — CRRT Simulator (healthcare-v2)
//
// All OBX codes are LOCAL (CRRT parameters are not standardised in LOINC).
// Each OBX carries the measurement name, value, unit, and reference range
// where clinically applicable.
// -----------------------------------------------------------------------
var c  = channelMap.get('crrt') || {};
var ts = channelMap.get('ts')   || new Date().toISOString();

var hl7ts = ts.replace(/[-:T]/g,'').substring(0,14);
var msgId = 'CRRT' + hl7ts;

function v(field) {
  var val = c[field];
  return (val !== null && val !== undefined) ? val : '';
}

function obxNM(seq, code, name, value, unit, refRange) {
  return 'OBX|' + seq + '|NM|' + code + '^' + name + '^LOCAL||' +
    value + '|' + unit + '|' + refRange + '||||F|||' + hl7ts;
}
function obxST(seq, code, name, value) {
  return 'OBX|' + seq + '|ST|' + code + '^' + name + '^LOCAL||' +
    value + '||||||F|||' + hl7ts;
}

var lines = [
  'MSH|^~\\&|CRRT_DEVICE|HOSPITAL_ICU|MIRTH_CONNECT|OPENEMR|' + hl7ts +
    '||ORU^R01^ORU_R01|' + msgId + '|P|2.5.1|||AL|AL|',
  'PID|1||PATIENT_001^^^HOSPITAL_ICU&HOSPITAL&L||Paciente^ICU||19800101|U|',
  'OBR|1|||CRRT-PANEL^CRRT Circuit Parameters^LOCAL|||' + hl7ts + '|||||||||||||||F',

  // Mode and status
  obxST(1,  'CRRT-MODE',       'Therapy mode',              v('mode')),
  obxST(2,  'CRRT-STATUS',     'Therapy status',            v('therapy_status')),

  // Flow rates
  obxNM(3,  'CRRT-BLOOD-FLOW', 'Blood pump speed',          v('blood_flow_ml_min'),       'mL/min',  '100-400'),
  obxNM(4,  'CRRT-UF-RATE',    'Net ultrafiltration rate',  v('uf_target_ml_h'),           'mL/h',    '0-3000'),
  obxNM(5,  'CRRT-DIAL-FLOW',  'Dialysate flow rate',       v('dialysate_flow_ml_h'),      'mL/h',    '0-3000'),
  obxNM(6,  'CRRT-REPL-FLOW',  'Replacement fluid rate',    v('replacement_flow_ml_h'),    'mL/h',    '0-3000'),

  // Circuit pressures
  obxNM(7,  'CRRT-ACCESS-P',   'Access (arterial) pressure', v('access_pressure_mmhg'),    'mm[Hg]',  '-250-0'),
  obxNM(8,  'CRRT-RETURN-P',   'Return (venous) pressure',   v('return_pressure_mmhg'),    'mm[Hg]',  '0-250'),
  obxNM(9,  'CRRT-TMP',        'Transmembrane pressure',     v('tmp_mmhg'),                'mm[Hg]',  '0-400'),

  // Filter health
  obxNM(10, 'CRRT-FILT-SAT',   'Filter saturation',         v('filter_saturation_pct'),   '%',       '0-100'),
  obxNM(11, 'CRRT-FILT-LIFE',  'Filter life remaining',     v('filter_life_remaining_pct'),'%',      '0-100'),
  obxNM(12, 'CRRT-FILT-TIME',  'Filter runtime',            v('filter_runtime_h'),         'h',       ''),

  // Fluid balance and anticoagulation
  obxNM(13, 'CRRT-NET-BAL',    'Net fluid balance',         v('net_balance_ml'),           'mL',      ''),
  obxNM(14, 'CRRT-HEPARIN',    'Heparin infusion rate',     v('heparin_iu_h'),             'IU/h',    ''),
];

tmp = lines.join('\r');
